// Package db holds the embedded SQL migrations and the migration runner.
// Query code generated by sqlc lands in the db/sqlc subpackage (from S1.1).
package db

import "embed"

// MigrationsFS embeds the golang-migrate SQL files so the migrate tool and the
// API (auto-migrate on boot) are fully self-contained — no files to ship.
//
//go:embed migrations/*.sql
var MigrationsFS embed.FS
